const config = {
  "previewFeatures": [],
  "clientVersion": "7.7.0",
  "engineVersion": "75cbdc1eb7150937890ad5465d861175c6624711",
  "activeProvider": "postgresql",
  "inlineSchema": "// prisma/schema.prisma\n// Digital Menu Platform — Full Database Schema\n// Using SQLite for local development (switch to PostgreSQL for production)\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ═══════════════════════════════════════════════════════\n// 1. Authentication & Users\n// ═══════════════════════════════════════════════════════\n\nmodel User {\n  id            String    @id @default(cuid())\n  name          String?\n  email         String    @unique\n  emailVerified DateTime?\n  passwordHash  String?\n  image         String?\n  phone         String?\n  role          String    @default(\"RESTAURANT_OWNER\") // ADMIN | RESTAURANT_OWNER\n  isActive      Boolean   @default(true)\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n\n  accounts      Account[]\n  sessions      Session[]\n  restaurants   Restaurant[]\n  subscriptions Subscription[]\n  notifications Notification[]\n\n  @@map(\"users\")\n}\n\nmodel Account {\n  id                String  @id @default(cuid())\n  userId            String\n  type              String\n  provider          String\n  providerAccountId String\n  refresh_token     String?\n  access_token      String?\n  expires_at        Int?\n  token_type        String?\n  scope             String?\n  id_token          String?\n  session_state     String?\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([provider, providerAccountId])\n  @@map(\"accounts\")\n}\n\nmodel Session {\n  id           String   @id @default(cuid())\n  sessionToken String   @unique\n  userId       String\n  expires      DateTime\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"sessions\")\n}\n\nmodel VerificationToken {\n  identifier String\n  token      String   @unique\n  expires    DateTime\n\n  @@unique([identifier, token])\n  @@map(\"verification_tokens\")\n}\n\n// ═══════════════════════════════════════════════════════\n// 2. Restaurants\n// ═══════════════════════════════════════════════════════\n\nmodel Restaurant {\n  id       String  @id @default(cuid())\n  userId   String\n  slug     String  @unique\n  isActive Boolean @default(true)\n\n  nameAr String\n  nameEn String?\n  nameTr String?\n  descAr String?\n  descEn String?\n  descTr String?\n\n  logoUrl        String?\n  primaryColor   String  @default(\"#FF6B35\")\n  secondaryColor String  @default(\"#1A1A2E\")\n\n  whatsapp  String?\n  phone     String?\n  instagram String?\n  facebook  String?\n  tiktok    String?\n  twitter   String?\n  telegram  String?\n\n  address         String?\n  latitude        Float?\n  longitude       Float?\n  googleMapsUrl   String?\n  googleReviewUrl String?\n\n  workingHours String? // JSON string\n\n  currency       String @default(\"SAR\")\n  taxPercent     Float  @default(0)\n  servicePercent Float  @default(0)\n  enabledLangs   String @default(\"ar\") // comma-separated: \"ar,en,tr\"\n  defaultLang    String @default(\"ar\")\n  menuViewMode   String @default(\"LIST\") // LIST | GRID\n\n  // Owner permissions (controlled by Admin)\n  ownerCanEditMenu     Boolean @default(false)\n  ownerCanEditBranding Boolean @default(false)\n  ownerCanEditSettings Boolean @default(false)\n  ownerCanManageTables Boolean @default(false)\n  ownerCanDeleteOrders Boolean @default(false)\n\n  aboutAr String?\n  aboutEn String?\n  aboutTr String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  user        User             @relation(fields: [userId], references: [id], onDelete: Cascade)\n  categories  Category[]\n  coverImages CoverImage[]\n  tables      Table[]\n  orders      Order[]\n  analytics   AnalyticsEvent[]\n  ratings     Rating[]\n\n  @@index([userId])\n  @@index([slug])\n  @@map(\"restaurants\")\n}\n\n// ═══════════════════════════════════════════════════════\n// 3. Cover Images (Slider)\n// ═══════════════════════════════════════════════════════\n\nmodel CoverImage {\n  id           String  @id @default(cuid())\n  restaurantId String\n  imageUrl     String\n  sortOrder    Int     @default(0)\n  isActive     Boolean @default(true)\n\n  restaurant Restaurant @relation(fields: [restaurantId], references: [id], onDelete: Cascade)\n\n  @@index([restaurantId])\n  @@map(\"cover_images\")\n}\n\n// ═══════════════════════════════════════════════════════\n// 4. Categories\n// ═══════════════════════════════════════════════════════\n\nmodel Category {\n  id           String @id @default(cuid())\n  restaurantId String\n\n  nameAr String\n  nameEn String?\n  nameTr String?\n\n  iconUrl String?\n  emoji   String?\n\n  sortOrder Int     @default(0)\n  isVisible Boolean @default(true)\n\n  // Scheduled menu: auto-show/hide by time of day\n  scheduleType  String? // \"ALL_DAY\" | \"BREAKFAST\" | \"LUNCH\" | \"DINNER\" | \"CUSTOM\"\n  scheduleStart String? // \"06:00\"\n  scheduleEnd   String? // \"11:00\"\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  restaurant Restaurant @relation(fields: [restaurantId], references: [id], onDelete: Cascade)\n  items      Item[]\n\n  @@index([restaurantId])\n  @@index([restaurantId, sortOrder])\n  @@map(\"categories\")\n}\n\n// ═══════════════════════════════════════════════════════\n// 5. Menu Items\n// ═══════════════════════════════════════════════════════\n\nmodel Item {\n  id         String @id @default(cuid())\n  categoryId String\n\n  nameAr String\n  nameEn String?\n  nameTr String?\n\n  descAr String?\n  descEn String?\n  descTr String?\n\n  price         Float\n  discountPrice Float?\n\n  calories  Int?\n  prepTime  Int?\n  allergens String?\n\n  badge       String? // NEW | POPULAR | OFFER\n  isAvailable Boolean @default(true)\n  sortOrder   Int     @default(0)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  category   Category    @relation(fields: [categoryId], references: [id], onDelete: Cascade)\n  images     ItemImage[]\n  sizes      ItemSize[]\n  extras     ItemExtra[]\n  orderItems OrderItem[]\n\n  @@index([categoryId])\n  @@index([categoryId, sortOrder])\n  @@map(\"items\")\n}\n\n// ═══════════════════════════════════════════════════════\n// 6. Item Images (Gallery)\n// ═══════════════════════════════════════════════════════\n\nmodel ItemImage {\n  id        String @id @default(cuid())\n  itemId    String\n  imageUrl  String\n  sortOrder Int    @default(0)\n\n  item Item @relation(fields: [itemId], references: [id], onDelete: Cascade)\n\n  @@index([itemId])\n  @@map(\"item_images\")\n}\n\n// ═══════════════════════════════════════════════════════\n// 7. Item Sizes\n// ═══════════════════════════════════════════════════════\n\nmodel ItemSize {\n  id     String @id @default(cuid())\n  itemId String\n\n  nameAr    String\n  nameEn    String?\n  nameTr    String?\n  price     Float\n  sortOrder Int     @default(0)\n\n  item Item @relation(fields: [itemId], references: [id], onDelete: Cascade)\n\n  @@index([itemId])\n  @@map(\"item_sizes\")\n}\n\n// ═══════════════════════════════════════════════════════\n// 8. Item Extras (Add-ons)\n// ═══════════════════════════════════════════════════════\n\nmodel ItemExtra {\n  id     String @id @default(cuid())\n  itemId String\n\n  nameAr    String\n  nameEn    String?\n  nameTr    String?\n  price     Float\n  sortOrder Int     @default(0)\n\n  item Item @relation(fields: [itemId], references: [id], onDelete: Cascade)\n\n  @@index([itemId])\n  @@map(\"item_extras\")\n}\n\n// ═══════════════════════════════════════════════════════\n// 9. Tables\n// ═══════════════════════════════════════════════════════\n\nmodel Table {\n  id           String @id @default(cuid())\n  restaurantId String\n\n  tableNumber String\n  qrCodeUrl   String?\n  isActive    Boolean @default(true)\n\n  restaurant Restaurant @relation(fields: [restaurantId], references: [id], onDelete: Cascade)\n  orders     Order[]\n\n  @@unique([restaurantId, tableNumber])\n  @@index([restaurantId])\n  @@map(\"tables\")\n}\n\n// ═══════════════════════════════════════════════════════\n// 10. Orders\n// ═══════════════════════════════════════════════════════\n\nmodel Order {\n  id           String @id @default(cuid())\n  restaurantId String\n  orderNumber  Int\n\n  customerName  String?\n  customerPhone String?\n\n  orderType       String // DINE_IN | TAKEAWAY | DELIVERY | SCHEDULED\n  tableId         String?\n  deliveryAddress String?\n  deliveryLat     Float?\n  deliveryLng     Float?\n  scheduledAt     DateTime?\n\n  subtotal      Float\n  taxAmount     Float @default(0)\n  serviceAmount Float @default(0)\n  total         Float\n\n  status String  @default(\"NEW\") // NEW | PREPARING | READY | COMPLETED | CANCELLED\n  notes  String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  restaurant Restaurant  @relation(fields: [restaurantId], references: [id], onDelete: Cascade)\n  table      Table?      @relation(fields: [tableId], references: [id])\n  items      OrderItem[]\n\n  @@unique([restaurantId, orderNumber])\n  @@index([restaurantId])\n  @@index([restaurantId, status])\n  @@index([restaurantId, createdAt])\n  @@map(\"orders\")\n}\n\n// ═══════════════════════════════════════════════════════\n// 11. Order Items\n// ═══════════════════════════════════════════════════════\n\nmodel OrderItem {\n  id      String @id @default(cuid())\n  orderId String\n  itemId  String\n\n  itemName   String\n  quantity   Int\n  unitPrice  Float\n  totalPrice Float\n\n  sizeName String?\n  extras   String? // JSON array: [\"extra1\",\"extra2\"]\n  notes    String?\n\n  order Order @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  item  Item  @relation(fields: [itemId], references: [id])\n\n  @@index([orderId])\n  @@map(\"order_items\")\n}\n\n// ═══════════════════════════════════════════════════════\n// 12. Subscription Plans\n// ═══════════════════════════════════════════════════════\n\nmodel Plan {\n  id     String  @id @default(cuid())\n  nameAr String\n  nameEn String?\n  slug   String  @unique\n\n  priceMonthly Float\n  priceYearly  Float\n\n  maxItems      Int?\n  maxCategories Int?\n\n  noAds             Boolean @default(false)\n  advancedAnalytics Boolean @default(false)\n  seoEnabled        Boolean @default(false)\n  multiViewMode     Boolean @default(false)\n  multiLanguage     Boolean @default(false)\n  aboutPage         Boolean @default(false)\n  workingHours      Boolean @default(false)\n  reviews           Boolean @default(false)\n  orderSystem       Boolean @default(false)\n  tableManagement   Boolean @default(false)\n  multiCoverImages  Boolean @default(false)\n  multiItemImages   Boolean @default(false)\n\n  isActive  Boolean @default(true)\n  sortOrder Int     @default(0)\n\n  subscriptions Subscription[]\n\n  @@map(\"plans\")\n}\n\nmodel Subscription {\n  id     String @id @default(cuid())\n  userId String\n  planId String\n\n  status       String @default(\"ACTIVE\") // ACTIVE | EXPIRED | CANCELLED | TRIAL\n  billingCycle String @default(\"MONTHLY\") // MONTHLY | YEARLY\n\n  startDate DateTime @default(now())\n  endDate   DateTime\n\n  paymentMethod String?\n  paymentId     String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n  plan Plan @relation(fields: [planId], references: [id])\n\n  @@index([userId])\n  @@index([userId, status])\n  @@map(\"subscriptions\")\n}\n\n// ═══════════════════════════════════════════════════════\n// 13. Analytics\n// ═══════════════════════════════════════════════════════\n\nmodel AnalyticsEvent {\n  id           String @id @default(cuid())\n  restaurantId String\n\n  eventType String // MENU_VIEW | CATEGORY_VIEW | ITEM_VIEW | ITEM_ADD_TO_CART | ORDER_PLACED | QR_SCAN\n\n  categoryId String?\n  itemId     String?\n\n  visitorIp String?\n  userAgent String?\n  referrer  String?\n  country   String?\n\n  createdAt DateTime @default(now())\n\n  restaurant Restaurant @relation(fields: [restaurantId], references: [id], onDelete: Cascade)\n\n  @@index([restaurantId])\n  @@index([restaurantId, eventType])\n  @@index([restaurantId, createdAt])\n  @@map(\"analytics_events\")\n}\n\n// ═══════════════════════════════════════════════════════\n// 14. Notifications (Real-time)\n// ═══════════════════════════════════════════════════════\n\nmodel Notification {\n  id           String  @id @default(cuid())\n  userId       String\n  restaurantId String?\n\n  type  String // NEW_ORDER | ORDER_UPDATED | SYSTEM\n  title String\n  body  String\n  data  String? // JSON string\n\n  isRead    Boolean  @default(false)\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId, isRead])\n  @@index([userId, createdAt])\n  @@map(\"notifications\")\n}\n\n// ═════════════════════════════════════════════════════════\n// 15. Ratings & Reviews\n// ═════════════════════════════════════════════════════════\n\nmodel Rating {\n  id           String  @id @default(cuid())\n  restaurantId String\n  itemId       String?\n  orderId      String?\n\n  stars        Int // 1-5\n  comment      String?\n  customerName String?\n\n  createdAt DateTime @default(now())\n\n  restaurant Restaurant @relation(fields: [restaurantId], references: [id], onDelete: Cascade)\n\n  @@index([restaurantId])\n  @@index([itemId])\n  @@map(\"ratings\")\n}\n"
}

